import type { FC } from "react";

import { ContactPage as ContactPageWidget } from "@/widgets/contact-page";

export const ContactPage: FC = () => <ContactPageWidget />;

"use client";

import { ArrowRight, CalendarDays, FileText, Mail } from "lucide-react";
import Image from "next/image";
import { useState } from "react";

import { useSubmitContact } from "@/shared/api/query-hooks/use-contacts";
import { Button } from "@/shared/ui/button/button";
import { Input } from "@/shared/ui/input/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/shared/ui/select";
import { Textarea } from "@/shared/ui/textarea/textarea";

const CONTACT_METHODS = [
  {
    id: "call",
    icon: <CalendarDays size={22} strokeWidth={1.5} className="text-[#44403c]" />,
    title: "Book a call",
    description: "Speak directly with a LuxFlow advisor.",
  },
  {
    id: "whatsapp",
    icon: (
      <Image
        src="/new-design-images/contact/wa-icon.svg"
        alt="WhatsApp"
        width={24}
        height={24}
      />
    ),
    title: "Chat on WhatsApp",
    description: "Instant support at your fingertips. Mon-Sun: 9 am – 6 pm",
  },
  {
    id: "email",
    icon: <Mail size={22} strokeWidth={1.5} className="text-[#44403c]" />,
    title: "Write an email",
    description: "contact@luxflow.com",
  },
  {
    id: "ticket",
    icon: <FileText size={22} strokeWidth={1.5} className="text-[#44403c]" />,
    title: "Submit a ticket",
    description: "Report bugs, or request technical support.",
  },
];

type FormState = {
  firstName: string;
  lastName: string;
  email: string;
  subject: string;
  message: string;
};

const INITIAL_FORM: FormState = {
  firstName: "",
  lastName: "",
  email: "",
  subject: "",
  message: "",
};

export function ContactPage() {
  const [form, setForm] = useState<FormState>(INITIAL_FORM);
  const [submitted, setSubmitted] = useState(false);

  const { mutate: submitContact, isPending, isError } = useSubmitContact();

  function handleChange(field: keyof FormState, value: string) {
    setForm((prev) => ({ ...prev, [field]: value }));
  }

  function handleSubmit(event: React.FormEvent) {
    event.preventDefault();
    submitContact(form, {
      onSuccess: () => {
        setSubmitted(true);
        setForm(INITIAL_FORM);
      },
    });
  }

  return (
    <div className="flex min-h-[calc(100vh-76px)] flex-col lg:flex-row">
      {/* Left panel — contact info */}
      <div className="flex flex-1 items-center justify-center bg-[#f5f3ef] px-6 py-16 lg:py-[100px]">
        <div className="flex w-full max-w-[500px] flex-col gap-16 lg:min-h-[725px] lg:justify-between">
          <p className="font-extralight font-new-serif text-[#44403c] text-[24px] leading-[1.2] sm:text-[28px] lg:text-[30px]">
            Whether you&apos;re considering a sale, a buyback, or simply
            exploring your options, our team is available to assist.
          </p>

          <div className="flex flex-col">
            {CONTACT_METHODS.map((method) => (
              <div key={method.id}>
                <div className="h-px bg-[#d6d3d1]" />
                <div className="flex items-center gap-5 py-[15px]">
                  <div className="shrink-0">{method.icon}</div>
                  <div className="flex flex-col">
                    <p className="font-bold font-new-sans text-[#44403c] text-[18px] leading-[1.5] tracking-[-0.18px]">
                      {method.title}
                    </p>
                    <p className="font-new-sans text-[#44403c] text-base leading-[1.5] tracking-[-0.16px]">
                      {method.description}
                    </p>
                  </div>
                </div>
              </div>
            ))}
            <div className="h-px bg-[#d6d3d1]" />
          </div>
        </div>
      </div>

      {/* Right panel — contact form */}
      <div className="relative flex flex-1 items-center justify-center overflow-hidden bg-[#ede9e3] px-6 py-16 lg:py-[100px]">
        <Image
          src="/new-design-images/carousel-waves.svg"
          alt=""
          fill
          aria-hidden
          className="pointer-events-none object-cover opacity-[0.15]"
        />

        <div className="relative z-10 flex w-full max-w-[487px] flex-col gap-8 overflow-hidden rounded-2xl bg-[#f5f3ef] px-6 py-10">
          {/* Card header */}
          <div className="flex flex-col items-center gap-5 text-center">
            <div className="relative h-[94px] w-[183px] shrink-0">
              {/* Tilted card behind the seal */}
              <div className="absolute flex items-center justify-center" style={{ top: "6.23%", left: "8.85%", right: "54.6%", bottom: "6.85%" }}>
                <Image
                  src="/new-design-images/contact/seal-card.svg"
                  alt=""
                  aria-hidden
                  width={59}
                  height={76}
                  style={{ transform: "rotate(6.22deg)" }}
                />
              </div>
              {/* Wax seal */}
              <div className="absolute top-0 h-[94px] w-[91px]" style={{ left: 46 }}>
                <Image
                  src="/new-design-images/contact/seal.png"
                  alt="LuxFlow"
                  fill
                  className="object-cover [filter:drop-shadow(0px_4px_12px_rgba(0,0,0,0.35))]"
                />
              </div>
            </div>
            <div>
              <h1 className="font-light font-new-serif text-[#000944] text-[24px] leading-[1.2]">
                Contact our team
              </h1>
              <p className="mt-1 font-new-sans text-[#44403c] text-base leading-[1.5] tracking-[-0.16px]">
                A LuxFlow advisor will review your enquiry and respond promptly.
              </p>
            </div>
          </div>

          {submitted ? (
            <div className="flex flex-col items-center gap-3 py-8 text-center">
              <p className="font-bold font-new-sans text-[#000944] text-lg">
                Message sent!
              </p>
              <p className="font-new-sans text-[#44403c] text-base leading-[1.5]">
                A LuxFlow advisor will get back to you shortly.
              </p>
              <button
                type="button"
                onClick={() => setSubmitted(false)}
                className="mt-2 font-new-sans text-[#44403c] text-sm underline underline-offset-2"
              >
                Send another message
              </button>
            </div>
          ) : (
            <form onSubmit={handleSubmit} className="flex flex-col gap-3">
              <div className="flex gap-3">
                <div className="flex flex-1 flex-col gap-1">
                  <label className="font-new-sans text-[#44403c] text-sm leading-[1.3]">
                    First Name*
                  </label>
                  <Input
                    required
                    value={form.firstName}
                    onChange={(event) => handleChange("firstName", event.target.value)}
                    className="h-12 rounded border-[#a8a29e] bg-[#f5f3ef] font-new-sans text-sm"
                  />
                </div>
                <div className="flex flex-1 flex-col gap-1">
                  <label className="font-new-sans text-[#44403c] text-sm leading-[1.3]">
                    Last Name*
                  </label>
                  <Input
                    required
                    value={form.lastName}
                    onChange={(event) => handleChange("lastName", event.target.value)}
                    className="h-12 rounded border-[#a8a29e] bg-[#f5f3ef] font-new-sans text-sm"
                  />
                </div>
              </div>

              <div className="flex flex-col gap-1">
                <label className="font-new-sans text-[#44403c] text-sm leading-[1.3]">
                  Email*
                </label>
                <Input
                  type="email"
                  required
                  value={form.email}
                  onChange={(event) => handleChange("email", event.target.value)}
                  className="h-12 rounded border-[#a8a29e] bg-[#f5f3ef] font-new-sans text-sm"
                />
              </div>

              <div className="flex flex-col gap-1">
                <label className="font-new-sans text-[#44403c] text-sm leading-[1.3]">
                  Subject
                </label>
                <Select
                  value={form.subject}
                  onValueChange={(value) => handleChange("subject", value)}
                >
                  <SelectTrigger className="h-12 rounded border-[#a8a29e] bg-[#f5f3ef] font-new-sans text-sm">
                    <SelectValue placeholder="Select an option" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="sale">Sale enquiry</SelectItem>
                    <SelectItem value="buyback">Buyback enquiry</SelectItem>
                    <SelectItem value="support">Technical support</SelectItem>
                    <SelectItem value="other">Other</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="flex flex-col gap-1">
                <label className="font-new-sans text-[#44403c] text-sm leading-[1.3]">
                  Your Message*
                </label>
                <Textarea
                  required
                  placeholder="Enter your message here"
                  value={form.message}
                  onChange={(event) => handleChange("message", event.target.value)}
                  className="h-[120px] resize-none rounded border-[#a8a29e] bg-[#f5f3ef] font-new-sans text-sm"
                />
              </div>

              {isError && (
                <p className="font-new-sans text-destructive text-sm">
                  Something went wrong. Please try again.
                </p>
              )}

              <Button
                type="submit"
                loading={isPending}
                className="w-full rounded bg-[#021171] font-medium font-new-sans text-[#f5f3ef] text-base hover:bg-[#021171]/90"
                size="small"
              >
                submit Message
                <ArrowRight size={18} />
              </Button>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}

