import type { ComponentProps, FC } from "react";

import { cn } from "../../lib/ui/cn";

type InputProps = ComponentProps<"input">;

export const Input: FC<InputProps> = (props) => {
  const { className, type, ...restProps } = props;

  return (
    <input
      className={cn(
        "focus:!border-primary focus:!ring-0 flex w-full rounded-lg border border-input bg-transparent px-[0.9375rem] py-[0.5625rem] font-serif text-sm leading-[1.2em] transition-colors file:border-0 file:bg-transparent file:font-medium file:text-sm placeholder:text-muted-foreground/70 focus:outline-none disabled:cursor-not-allowed disabled:opacity-50",
        className,
      )}
      type={type}
      {...restProps}
    />
  );
};

